mapper.select:
SELECT COUNT(*) 
FROM User_Coupon 
WHERE user_id = #{userId} 
  AND coupon_code = #{couponCode}

SELECT COM_NAME
FROM COMPANY
WHERE USER_ID = #{userId}


SELECT M.user_id 
FROM member M
JOIN user_detail UD ON M.user_id = UD.user_id
WHERE UD.user_name = #{userName} 
  AND M.phone = #{phone}
UNION

SELECT M.user_id 
FROM member M
JOIN company C ON M.user_id = C.user_id
WHERE C.ceo_name = #{userName} 
  AND M.phone = #{phone}

SELECT COUNT(*) FROM (

    SELECT M.user_id FROM member M
    JOIN user_detail UD ON M.user_id = UD.user_id
    WHERE M.user_id = #{userId} AND UD.user_name = #{userName} AND M.phone = #{phone}
    UNION

    SELECT M.user_id FROM member M
    JOIN company C ON M.user_id = C.user_id
    WHERE M.user_id = #{userId} AND C.ceo_name = #{userName} AND M.phone = #{phone}
) AS combined_user

